+    ] {
+        fconn.execute(s).unwrap();
+        rconn.execute_batch(s).unwrap();
+    }
+
+    // Complex WHERE with AND/OR
+    for s in
+        &["UPDATE uwc SET score = score + 5 WHERE category = 'A' AND active = 1 AND score < 90"]
